DROP TABLE IF EXISTS `books`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `books` (
  `book_id` bigint NOT NULL AUTO_INCREMENT COMMENT '书籍ID',
  `title` varchar(200) NOT NULL COMMENT '书名',
  `author` varchar(100) DEFAULT NULL COMMENT '作者',
  `isbn` varchar(20) DEFAULT NULL COMMENT 'ISBN号',
  `publisher` varchar(100) DEFAULT NULL COMMENT '出版社',
  `publish_date` date DEFAULT NULL COMMENT '出版日期',
  `category_id` bigint DEFAULT NULL COMMENT '分类ID',
  `price` decimal(10,2) DEFAULT NULL COMMENT '价格',
  `stock` int DEFAULT '0' COMMENT '库存数量',
  `pages` int DEFAULT NULL COMMENT '页数',
  `tags` text COMMENT '标签(JSON格式)',
  `avg_rating` decimal(3,2) DEFAULT '0.00' COMMENT '平均评分',
  `rating_count` int DEFAULT '0' COMMENT '评分人数',
  `view_count` int NOT NULL DEFAULT '0' COMMENT '????',
  `collect_count` int NOT NULL DEFAULT '0' COMMENT '????',
  `series_info` varchar(200) DEFAULT NULL COMMENT '系列信息',
  `description` text COMMENT '书籍简介',
  `preview_content` text COMMENT '试读内容',
  `ebook_url` varchar(255) DEFAULT NULL COMMENT '电子书文件URL（如/uploads/ebooks/123.epub）',
  `ebook_type` varchar(10) DEFAULT NULL COMMENT '电子书类型：epub/pdf',
  `ebook_size` bigint DEFAULT NULL COMMENT '电子书文件大小（字节）',
  `cover_image` varchar(255) DEFAULT NULL COMMENT '封面图片URL',
  `status` tinyint DEFAULT '1' COMMENT '状态: 0-下架, 1-上架',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`book_id`),
  UNIQUE KEY `isbn` (`isbn`),
  KEY `category_id` (`category_id`),
  CONSTRAINT `books_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `categories` (`category_id`)
) ENGINE=InnoDB AUTO_INCREMENT=972 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='书籍表';
