INSERT INTO `books` VALUES (1,'三体','刘慈欣','9787536692930','重庆出版社','2008-01-01',12,36.00,10,NULL,'[\"科幻\", \"未来\", \"硬科幻\", \"三体系列\"]',4.17,6,503,1,NULL,'地球往事三部曲之一','科学边界学会在选定的更深人的模型上工作，比如说你描写了一个人物，那你就应该知道这个人物的内心世界、思维过程以及他会如何面对各种情况。另外，一个小说最重要的也是最困难的，就是刻画人物。因为小说就是通过人物来反映社会现实的。\n\n叶文洁看到的雷达峰，是一个在夕阳中发着金属光泽的圆锥体，直径约有三十米，高约五十米，底部由六根粗壮的支架支撑着。它坐落在峰顶，像一个巨大的金属蘑菇。这是红岸基地的主体建筑——发射主机房。\n\n基地的大门在山脚下，从山脚到峰顶有一条简易公路，全长约四公里。叶文洁乘坐的吉普车沿这条路缓缓向上行驶。随着高度的增加，山谷中的人烟渐渐稀少，道路两旁的树木也越来越矮小，最后变成了灌木丛和草甸。\n\n雷达峰的底部由六根直径约两米的钢柱支撑，每根钢柱都深插入岩石中。钢柱之间用横梁连接，形成了一个坚固的支撑结构。主机房的外壁是银灰色的金属板，在夕阳下反射着耀眼的光芒。\n\n叶文洁被带到主机房的控制室。房间不大，约有二十平方米，四周都是仪表盘和控制台。正面是一面巨大的玻璃窗，可以看到外面的山谷和远处的城市。控制台前坐着几个穿军装的工作人员，他们正在操作各种仪器。\n\n一位中年军官走过来，向叶文洁敬了个礼，说：\"叶文洁同志，欢迎来到红岸基地。我是基地的政委雷志成。\"叶文洁点了点头，没有说话。雷志成继续说：\"从今天起，你将在这里工作。你的任务是参与一项重要的科研项目。具体内容，明天会有人详细向你介绍。\"','/uploads/ebooks/1.pdf','pdf',65166,'/covers/1.jpg',1,'2026-06-23 16:42:24','2026-06-30 14:50:45'),(2,'活着','余华','9787506365437','作家出版社','2012-08-01',10,20.00,15,NULL,'[\"现实\", \"当代文学\", \"现实主义\", \"余华\"]',4.00,6,500,0,NULL,'余华经典作品',NULL,'/uploads/ebooks/2.epub','epub',4819,'/covers/2.jpg',1,'2026-06-23 16:42:24','2026-06-30 14:50:45'),(3,'百年孤独','加西亚·马尔克斯','9787544253994','南海出版公司','2011-06-01',1,39.50,8,NULL,'[\"文学\", \"经典\", \"魔幻现实主义\", \"诺贝尔文学奖\"]',4.00,3,500,0,NULL,'魔幻现实主义文学代表作',NULL,NULL,NULL,NULL,'/covers/3.jpg',1,'2026-06-23 16:42:24','2026-06-30 14:50:45'),(4,'数据结构与算法','严蔚敏','9787302033141','清华大学出版社','2011-11-01',4,39.00,20,NULL,'[\"编程\", \"计算机\"]',0.00,0,150,0,NULL,'计算机专业经典教材',NULL,NULL,NULL,NULL,'/covers/4.jpg',1,'2026-06-23 16:42:24','2026-06-30 14:50:45'),(5,'Java编程思想','Bruce Eckel','9787111213826','机械工业出版社','2007-06-01',4,108.00,12,NULL,'[\"编程\", \"计算机\"]',0.00,0,150,0,NULL,'Java领域经典著作',NULL,NULL,NULL,NULL,'/covers/5.jpg',1,'2026-06-23 16:42:24','2026-06-30 14:50:45'),(6,'围城','钱钟书','9787020024759','人民文学出版社','1947-01-01',1,25.00,18,NULL,'[\"文学\", \"经典\", \"讽刺文学\", \"现代文学\", \"讽刺\"]',0.00,0,300,0,NULL,'钱钟书代表作,以幽默讽刺笔调描写知识分子的婚姻与人生困境。',NULL,NULL,NULL,NULL,'/covers/6.jpg',1,'2026-06-25 08:40